pipeline.evaluate:
(async () => {
  let attempts = 0;

  while (attempts < 20) {
    const bookmarkBtn = document.querySelector('[data-testid="bookmark"]');
    if (bookmarkBtn) return [{ status: 'success', message: 'Tweet is not bookmarked' }];

    const removeBtn = document.querySelector('[data-testid="removeBookmark"]');
    if (removeBtn) {
      removeBtn.click();
      await new Promise(r => setTimeout(r, 1000));
      const verify = document.querySelector('[data-testid="bookmark"]');
      if (verify) return [{ status: 'success', message: 'Tweet successfully removed from bookmarks' }];
      return [{ status: 'failed', message: 'Unbookmark action initiated but UI did not update' }];
    }

    await new Promise(r => setTimeout(r, 500));
    attempts++;
  }

  return [{ status: 'failed', message: 'Could not find Remove Bookmark button' }];
})()
